        // --- Helper Function for Centering Modals ---
        function positionModalCenter(modalDialogElement) {
            if (!modalDialogElement) {
                console.error("Modal dialog element not provided for centering.");
                return;
            }

            const viewportWidth = window.innerWidth;
            const viewportHeight = window.innerHeight;
            const offset = 15; // Minimum space from viewport edges

            // Ensure the element is visible (or temporarily visible) to measure accurately
            const overlay = modalDialogElement.closest('.modal-overlay, .settings-panel'); // Find parent overlay/panel
            let overlayOriginallyHidden = false;
            let overlayOriginalVisibility = '';
            let overlayOriginalDisplay = '';
            let overlayWasHiddenByClass = false;

            if (overlay) {
                 overlayWasHiddenByClass = overlay.classList.contains('hidden');
                 const computedDisplay = getComputedStyle(overlay).display;

                 if (overlayWasHiddenByClass || computedDisplay === 'none') {
                    overlayOriginallyHidden = true;
                    overlayOriginalVisibility = overlay.style.visibility;
                    overlayOriginalDisplay = overlay.style.display;
                    overlay.style.visibility = 'hidden'; // Keep hidden but allow layout calculation
                    overlay.style.display = 'block';    // Or 'flex', ensure it takes space
                    if (overlayWasHiddenByClass) overlay.classList.remove('hidden'); // Temporarily remove class
                 }
            }

            // Also ensure the dialog itself isn't display:none or visibility:hidden
            let dialogOriginalDisplay = modalDialogElement.style.display;
            let dialogOriginalVisibility = modalDialogElement.style.visibility;
            let dialogOriginalPosition = modalDialogElement.style.position; // Store original position

            modalDialogElement.style.visibility = 'hidden'; // Ensure measurable
            modalDialogElement.style.display = 'block'; // Or appropriate display type
            modalDialogElement.style.position = 'absolute'; // Needed for offsetWidth/Height calculation

            const modalWidth = modalDialogElement.offsetWidth;
            const modalHeight = modalDialogElement.offsetHeight;

             // Restore original styles after measurement
             modalDialogElement.style.display = dialogOriginalDisplay;
             modalDialogElement.style.visibility = dialogOriginalVisibility;
             modalDialogElement.style.position = dialogOriginalPosition;

            if (overlayOriginallyHidden && overlay) {
                if (overlayWasHiddenByClass) overlay.classList.add('hidden'); // Re-add class if removed
                overlay.style.visibility = overlayOriginalVisibility;
                overlay.style.display = overlayOriginalDisplay;
            }

            if (!modalWidth || !modalHeight || modalWidth <= 0 || modalHeight <= 0) {
                console.warn("Could not get valid modal dimensions for centering. Applying default styles.");
                modalDialogElement.style.position = 'absolute';
                modalDialogElement.style.top = '10%'; // Fallback position
                modalDialogElement.style.left = '10%';
                modalDialogElement.style.transform = 'none';
                return;
            }

            let top = (viewportHeight - modalHeight) / 2;
            let left = (viewportWidth - modalWidth) / 2;

            // Clamp to viewport with offset
            top = Math.max(offset, Math.min(top, viewportHeight - modalHeight - offset));
            left = Math.max(offset, Math.min(left, viewportWidth - modalWidth - offset));

            modalDialogElement.style.position = 'absolute'; // Ensure absolute positioning
            modalDialogElement.style.top = `${top}px`;
            modalDialogElement.style.left = `${left}px`;
            modalDialogElement.style.transform = 'none'; // Remove any centering transforms like translate(-50%, -50%)
            console.log(`DEBUG: Centered modal at top: ${top}px, left: ${left}px`);
        }

