            // Extract Header Tags
            const headerTags = {
                TITLE: (value) => { data.title = value; },
                IMPORTANT_CHARACTERS: (value) => {
                    const characters = [];
                    const characterRegex = /([^,{}\s][^,{}]*?)\s*\{((?:[^{}]|\{[^{}]*\})*)\}\s*(?:,|$)/g;
                    let charMatch;
                    while ((charMatch = characterRegex.exec(value)) !== null) {
                        characters.push({ name: charMatch[1].trim(), description: charMatch[2].trim() });
                    }
                    data.importantCharacters = characters;
