                EXTERNAL_AREAS: (value) => { data.externalAreas = value.split(',').map(name => name.trim()).filter(name => name); },
                MOVEBLOCK: (value) => { data.moveBlocked = value.toUpperCase() === 'YES'; },
                CURRENT_POS: (value) => {
                    const coords = value.match(/^(\d+)\|(\d+)$/);
                    if (coords) {
                        data.currentUserPosition.x = parseInt(coords[1], 10);
                        data.currentUserPosition.y = parseInt(coords[2], 10);
                    }
                },
                MONEY: (value) => { data.money = parseInt(value, 10) || 0; },
                SHOP_ITEMS: (value) => {
                    data.shop = value.split(',').map(itemStr => {
                        const parts = itemStr.trim().split('|');
                        if (parts.length >= 4) {
                            return { name: parts[0], price: parseInt(parts[1], 10) || 0, description: parts[2], category: parts[3] };
                        }
                        return null;
                    }).filter(item => item);
                },
                INVENTORY: (value) => {
                    data.inventory = value.split(',').map(itemStr => {
                        const parts = itemStr.trim().split('|');
                        if (parts.length >= 3) {
