            // Updated regex to include new tags, including IMPORTANT_CHARACTERS
            const headerRegex = /^\[(TITLE|IMPORTANT_CHARACTERS|EXTERNAL_AREAS|MOVEBLOCK|CURRENT_POS|MONEY|SHOP_ITEMS|INVENTORY):\s*(.*?)\]\s*\n?/i;
            while ((headerMatch = processedText.match(headerRegex)) !== null) {
                const tagName = headerMatch[1].toUpperCase();
                const tagValue = headerMatch[2].trim();
                if (headerTags[tagName]) {
                    headerTags[tagName](tagValue);
                    console.log(`Extracted ${tagName}:`, tagValue);
                }
                processedText = processedText.substring(headerMatch[0].length).trimStart();
            }

            // Process Location and Road Lines
            try {
                const lines = processedText.split('\n').map(line => line.trim()).filter(line => line);
                let currentMainLocation = null;
                 console.log(`Processing ${lines.length} lines of location/road data...`);

                for (const line of lines) {
                    const mainLocationRegex = /^\[([^|\]]+)(?:\|(\d+)\|(\d+))?(?:\|(\d+)\|(\d+))?\]$/;
                    const mainLocationMatch = line.match(mainLocationRegex);
                    const subLocationMatch = line.match(/^-\s*([^:]+?)\s*:(.*)/);
                    const roadMatch = line.match(/^\[ROAD\|([^|]+)\|(\d+)(?:\|([^\]]+))?\]$/);

                    if (roadMatch) {
                        if (currentMainLocation) {
                            data.locations.push(currentMainLocation);
                            currentMainLocation = null;
                        }
                        const pointsStr = roadMatch[1];
                        const width = parseInt(roadMatch[2], 10);
                        const color = roadMatch[3] || '#888888';
                        const points = pointsStr.split(';').map(p => p.trim()).filter(p => p.includes(',')).map(p => {
                            const coords = p.split(',');
                            return { x: parseInt(coords[0], 10), y: parseInt(coords[1], 10) };
                        }).filter(p => !isNaN(p.x) && !isNaN(p.y));

                        if (points.length >= 2) {
                            data.roads.push({ points: points.map(p => `${p.x},${p.y}`).join(' '), width, color });
                             console.log(`  Found road: ${points.length} points, width ${width}, color ${color}`);
                        } else {
                             console.warn(`  Skipping invalid road definition: ${line}`);
                        }
                    } else if (mainLocationMatch) {
                        const potentialMainName = mainLocationMatch[1].trim();
                        // Updated to check for IMPORTANT_CHARACTERS instead of CONVERSING
                        if (['TITLE', 'IMPORTANT_CHARACTERS', 'EXTERNAL_AREAS', 'MOVEBLOCK', 'ROAD', 'CURRENT_POS'].includes(potentialMainName.toUpperCase())) {
                             console.warn(`  Skipping line resembling a header tag: "${line}"`);
                             continue;
                        }
                        const xCoord = mainLocationMatch[2] ? parseInt(mainLocationMatch[2], 10) : null;
                        const yCoord = mainLocationMatch[3] ? parseInt(mainLocationMatch[3], 10) : null;
                        const wCoord = mainLocationMatch[4] ? parseInt(mainLocationMatch[4], 10) : null;
                        const hCoord = mainLocationMatch[5] ? parseInt(mainLocationMatch[5], 10) : null;

                        if (currentMainLocation) {
                            data.locations.push(currentMainLocation);
                        }
                        currentMainLocation = {
                            name: potentialMainName,
                            x: xCoord, y: yCoord, width: wCoord, height: hCoord,
                            subLocations: []
                        };
                         console.log(`    Started new main location: "${potentialMainName}"`);

                    } else if (subLocationMatch && currentMainLocation) {
                        const subName = subLocationMatch[1].trim();
                        const charactersText = subLocationMatch[2] ? subLocationMatch[2].trim() : '';
                        const characters = [];
                        try {
                            const characterRegex = /([^,{}\s][^,{}]*?)\s*(?:\{([^}]*)\})?\s*(?:,|$)/g;
                            let charMatch;
                            characterRegex.lastIndex = 0;

                            while ((charMatch = characterRegex.exec(charactersText)) !== null) {
                                let parsedName = charMatch[1] ? charMatch[1].trim() : null;
                                let parsedDescription = charMatch[2] ? charMatch[2].trim() : null;

                                if (parsedName && parsedName.length > 0 && parsedName.toLowerCase() !== 'không có') {
                                    parsedName = parsedName.replace(/[\])}]+$/, '').trim();
                                    // Check if the character is already in importantCharacters
                                    const isImportant = data.importantCharacters.some(ic => ic.name === parsedName);
                                    if (parsedName && !isImportant) { // Only add if not an important character
                                        characters.push({ name: parsedName, description: parsedDescription });
                                         console.log(`        Added NPC: "${parsedName}" ${parsedDescription ? '(with description)' : ''}`);
                                    } else if (parsedName && isImportant) {
                                         console.log(`        Skipped important character in sub-location: "${parsedName}"`);
                                    }
                                } else if (parsedName) {
                                     console.log(`        Skipped character (e.g., 'Không có'): "${parsedName}"`);
                                }
                                if (charMatch[0].length === 0) { characterRegex.lastIndex++; }
                                if (characterRegex.lastIndex === charMatch.index) { break; }
                            }
                        } catch (charError) {
                             console.error(`      Error parsing characters for sublocation "${subName}":`, charError);
                        }
                        currentMainLocation.subLocations.push({ name: subName, characters: characters });
                         console.log(`    Finished sub-location "${subName}", found ${characters.length} characters.`);
                    } else {
                         // Check for BULLETS line AFTER checking for locations/roads
                         const bulletsMatch = line.match(/^\[BULLETS:\s*(.*)\]$/i);
                         if (bulletsMatch) {
                             const bulletsContent = bulletsMatch[1].trim();
                             data.bullets = bulletsContent.split(';;').map(b => b.trim()).filter(b => b);
                             console.log(`  Extracted ${data.bullets.length} bullets.`);
                         } else {
                             console.log(`  Skipping line (not main/sub location, road, or bullets): "${line}"`);
                         }
                    }
                }

                if (currentMainLocation) {
                    data.locations.push(currentMainLocation);
                }

                 console.log(`Finished parsing locations and roads. Total main locations: ${data.locations.length}, Total roads: ${data.roads.length}, Current Pos: (${data.currentUserPosition.x ?? 'N/A'}, ${data.currentUserPosition.y ?? 'N/A'})`);

                // The logic for adding conversing partners to the current sub-location is removed
                // as important characters are now handled by [IMPORTANT_CHARACTERS] tag globally.

                 console.log("Map data parsing complete. Final data structure (locations might be large):", { ...data, locations: `[${data.locations.length} main locations]`, roads: `[${data.roads.length} roads]` });
                return data;
            } catch (error) {
                 console.error("Error during map data parsing process:", error);
                return null;
            }
        }

        // --- Helper: Format mapData object back to string ---
        function formatMapDataToString(mapDataToFormat) {
            if (!mapDataToFormat) return '<map_data></map_data>'; // Handle null input

            let output = '<map_data>\n';

            // Header Tags
            if (mapDataToFormat.title) output += `[TITLE: ${mapDataToFormat.title}]\n`;
            if (mapDataToFormat.importantCharacters && mapDataToFormat.importantCharacters.length > 0) {
                 const importantCharsStr = mapDataToFormat.importantCharacters.map(char => `${char.name}{${char.description || ''}}`).join(','); // Ensure description is included
                 output += `[IMPORTANT_CHARACTERS: ${importantCharsStr}]\n`;
            }
            if (mapDataToFormat.externalAreas && mapDataToFormat.externalAreas.length > 0) output += `[EXTERNAL_AREAS: ${mapDataToFormat.externalAreas.join(',')}]\n`;
            output += `[MOVEBLOCK: ${mapDataToFormat.moveBlocked ? 'YES' : 'NO'}]\n`;
            if (mapDataToFormat.currentUserPosition && typeof mapDataToFormat.currentUserPosition.x === 'number' && typeof mapDataToFormat.currentUserPosition.y === 'number') {
                output += `[CURRENT_POS: ${mapDataToFormat.currentUserPosition.x}|${mapDataToFormat.currentUserPosition.y}]\n`;
            }
            if (typeof mapDataToFormat.money === 'number') output += `[MONEY: ${mapDataToFormat.money}]\n`;
            if (mapDataToFormat.shop && mapDataToFormat.shop.length > 0) {
                const shopStr = mapDataToFormat.shop.map(item => `${item.name}|${item.price}|${item.description}|${item.category}`).join(',');
                output += `[SHOP_ITEMS: ${shopStr}]\n`;
            }
            if (mapDataToFormat.inventory && mapDataToFormat.inventory.length > 0) {
                const invStr = mapDataToFormat.inventory.map(item => `${item.name}|${item.description}|${item.category}`).join(',');
                output += `[INVENTORY: ${invStr}]\n`;
            }

            // Roads
            if (mapDataToFormat.roads && mapDataToFormat.roads.length > 0) {
                mapDataToFormat.roads.forEach(road => {
                    // Convert points string back to X1,Y1;X2,Y2 format
                    const pointsStr = road.points.split(' ').map(p => p.replace(',', ',')).join(';');
                    output += `[ROAD|${pointsStr}|${road.width}|${road.color}]\n`;
                });
            }

            // Locations and Sub-locations
            if (mapDataToFormat.locations && mapDataToFormat.locations.length > 0) {
                mapDataToFormat.locations.forEach(loc => {
                    let locHeader = `[${loc.name}`;
                    if (loc.x !== null && loc.y !== null) locHeader += `|${loc.x}|${loc.y}`;
                    if (loc.width !== null && loc.height !== null) locHeader += `|${loc.width}|${loc.height}`;
                    locHeader += ']';
                    output += `${locHeader}\n`;

                    if (loc.subLocations && loc.subLocations.length > 0) {
                        loc.subLocations.forEach(sub => {
                            output += `- ${sub.name}: `;
                            if (sub.characters && sub.characters.length > 0) {
                                const charStr = sub.characters.map(char => {
                                    let charOutput = char.name;
                                    if (char.description) {
                                        // Ensure description doesn't contain invalid characters for the format if needed
                                        charOutput += `{${char.description}}`;
                                    }
                                    return charOutput;
                                }).join(', ');
                                output += `${charStr}\n`;
                            } else {
                                output += `Không có\n`; // Indicate no characters
                            }
                        });
                    }
                });
            }

            // Bullets
            if (mapDataToFormat.bullets && mapDataToFormat.bullets.length > 0) {
                output += `[BULLETS: ${mapDataToFormat.bullets.join(';;')}]\n`;
            }

            output += '</map_data>';
            console.log("Formatted map data string:", output); // Debug log
            return output;
        }

        function renderMapInterface(mapData) {
            const titleElement = document.getElementById('map-title');
            titleElement.textContent = (mapData && mapData.title) ? mapData.title : 'Điều hướng bản đồ chung';

            if (!mapData || !mapData.locations) {
                 document.getElementById('main-locations').innerHTML = '<p class="error-message">Tải dữ liệu bản đồ thất bại</p>';
                 document.getElementById('sub-locations').classList.add('hidden');
                 document.getElementById('location-details').classList.add('hidden');
                 document.getElementById('movement-alert').classList.add('hidden');
                 return;
            }
            hasMoveBlock = mapData.moveBlocked;
            document.getElementById('movement-alert').classList.toggle('hidden', !hasMoveBlock); // Show/hide based on data

            const svgMap = document.getElementById('visual-map');
            const tooltip = document.getElementById('map-tooltip');
            const svgNS = "http://www.w3.org/2000/svg";
            svgMap.innerHTML = ''; // Clear previous SVG content

            // Update global data (Shop/Inventory related)
            playerGold = mapData.money || 0;
            shopItems = mapData.shop || [];
            inventoryItems = mapData.inventory || [];
            updatePlayerGold(); // Update display

            // Render Roads FIRST
            if (mapData.roads && mapData.roads.length > 0) {
                mapData.roads.forEach(road => {
                    const polyline = document.createElementNS(svgNS, 'polyline');
                    polyline.setAttribute('points', road.points);
                    polyline.setAttribute('stroke', road.color);
                    polyline.setAttribute('stroke-width', road.width);
                    polyline.setAttribute('fill', 'none');
                    polyline.setAttribute('stroke-linecap', 'round');
                    polyline.setAttribute('stroke-linejoin', 'round');
                    polyline.classList.add('map-road');
                    svgMap.appendChild(polyline);
                });
            }

            // Render Locations on SVG
            const defaultWidth = 100;
            const defaultHeight = 60;

            mapData.locations.forEach(location => {
                if (location && typeof location.name === 'string' && location.x !== null && location.y !== null) {
                    const locWidth = location.width || defaultWidth;
                    const locHeight = location.height || defaultHeight;
                    const labelOffsetDy = locHeight / 2 + 5;

                    const group = document.createElementNS(svgNS, 'g');
                    group.setAttribute('transform', `translate(${location.x}, ${location.y})`);
                    group.classList.add('map-location-group');
                    group.dataset.location = location.name;
                    group.style.pointerEvents = 'all';

                    const rect = document.createElementNS(svgNS, 'rect');
                    rect.style.pointerEvents = 'all';
                    rect.setAttribute('width', locWidth);
                    rect.setAttribute('height', locHeight);
                    rect.setAttribute('rx', 5);
                    rect.setAttribute('ry', 5);
                    rect.classList.add('map-location-rect');
                    group.addEventListener('click', () => selectMainLocation(location));
                    group.appendChild(rect);

                    const text = document.createElementNS(svgNS, 'text');
                    text.setAttribute('x', locWidth / 2);
                    text.setAttribute('y', labelOffsetDy);
                    text.classList.add('map-location-label');
                    text.textContent = location.name;
                    group.appendChild(text);

                    if (tooltip) {
                        group.addEventListener('mouseenter', (e) => {
                            tooltip.textContent = location.name;
                            tooltip.style.left = `${e.clientX + 10}px`;
                            tooltip.style.top = `${e.clientY + 10}px`;
                            tooltip.classList.add('visible');
                        });
                        group.addEventListener('mousemove', (e) => {
                            tooltip.style.left = `${e.clientX + 10}px`;
                            tooltip.style.top = `${e.clientY + 10}px`;
                        });
                        group.addEventListener('mouseleave', () => {
                            tooltip.classList.remove('visible');
                        });
                    }
                    svgMap.appendChild(group);
                } else if (location && typeof location.name === 'string') {
                    console.warn(`Location "${location.name}" is missing coordinates and won't be rendered visually.`);
                }
            });

            resetSelection(false);

            const switchAreaBtn = document.getElementById('switch-area-button');
            const hasExternalAreas = mapData.externalAreas && mapData.externalAreas.length > 0;
            switchAreaBtn.classList.toggle('hidden', !hasExternalAreas);
            if (hasExternalAreas) {
                const newSwitchAreaBtn = switchAreaBtn.cloneNode(true); // Re-attach listener
                switchAreaBtn.parentNode.replaceChild(newSwitchAreaBtn, switchAreaBtn);
                newSwitchAreaBtn.addEventListener('click', () => showExternalAreas(mapData.externalAreas));
            }

            // Render Current User Position (Red Dot)
            if (mapData.currentUserPosition && typeof mapData.currentUserPosition.x === 'number' && typeof mapData.currentUserPosition.y === 'number') {
                const userDot = document.createElementNS(svgNS, 'circle');
                userDot.setAttribute('cx', mapData.currentUserPosition.x);
                userDot.setAttribute('cy', mapData.currentUserPosition.y);
                userDot.setAttribute('r', 6);
                userDot.setAttribute('fill', 'red');
                userDot.setAttribute('stroke', 'white');
                userDot.setAttribute('stroke-width', 1.5);
                userDot.classList.add('current-user-position');
                userDot.style.pointerEvents = 'none';
                svgMap.appendChild(userDot);
                 console.log(`Rendered user position dot at (${mapData.currentUserPosition.x}, ${mapData.currentUserPosition.y})`);
            } else {
                 console.log("User position coordinates not available or invalid, skipping dot rendering.");
            }
        }


        function selectMainLocation(location) {
            console.log("selectMainLocation called with location:", location ? location.name : 'undefined/null');
            if (!location || !location.subLocations) {
                console.log("selectMainLocation returning early: location or subLocations missing.");
                return;
            }
            console.log("selectMainLocation proceeding for:", location.name);

            selectedMain = location;
            selectedSub = null;
            selectedCharacterName = null;
            updateActionButtonState();

            document.getElementById('location-details').classList.add('hidden');
            document.getElementById('sub-locations').classList.add('hidden');
            document.getElementById('switch-area-button').classList.remove('selected');

            // Update selection state for SVG elements
            document.querySelectorAll('#visual-map .map-location-group').forEach(group => {
                group.classList.toggle('selected', group.dataset.location === location.name);
            });

            const subLocationsContainer = document.getElementById('sub-locations');
            subLocationsContainer.innerHTML = '';

            if (location.subLocations.length === 0) {
                 subLocationsContainer.innerHTML = '<p class="info-message">Không có địa điểm khám phá cụ thể trong khu vực này.</p>';
                 subLocationsContainer.classList.remove('hidden');
                 return;
            }

            location.subLocations.forEach(subLocation => {
                if (!subLocation || typeof subLocation.name !== 'string') return;
                const button = document.createElement('button');
                button.className = 'sub-location-button';
                const iconClass = getIconClassForLocation(subLocation.name);
                button.innerHTML = `<i class="fas ${iconClass}"></i> ${subLocation.name}`;
                button.dataset.sublocation = subLocation.name;
                button.addEventListener('click', () => selectSubLocation(subLocation));
                subLocationsContainer.appendChild(button);
            });

            subLocationsContainer.classList.remove('hidden');
        }

        function selectSubLocation(subLocation) {
            if (!subLocation || !subLocation.characters || !selectedMain) return;

            selectedSub = subLocation;
            selectedCharacterName = null;
            updateActionButtonState();

            document.querySelectorAll('#sub-locations .sub-location-button').forEach(btn => {
                btn.classList.toggle('selected', btn.dataset.sublocation === subLocation.name);
            });

            document.getElementById('selected-location').textContent = `${selectedMain.name} - ${subLocation.name}`;
            const charactersContainer = document.getElementById('location-characters');
            charactersContainer.innerHTML = ''; // Clear previous characters

            // Get list of important character names for filtering
            const importantCharacterNames = (mapData && mapData.importantCharacters) ? mapData.importantCharacters.map(ic => ic.name) : [];
            let nonImportantCharactersFound = false; // Flag to check if any non-important characters are rendered

            if (subLocation.characters && subLocation.characters.length > 0) {
                subLocation.characters.forEach(characterObj => {
                    if (!characterObj || !characterObj.name) return;

                    // Filter out important characters from sub-location display
                    if (importantCharacterNames.includes(characterObj.name)) {
                        console.log(`Filtering out important character "${characterObj.name}" from sub-location "${subLocation.name}"`);
                        return; // Skip this character, as they are an important character
                    }

                    // This is a non-important character, render it
                    const charButton = document.createElement('button');
                    charButton.className = 'character-item';
                    charButton.dataset.characterName = characterObj.name;
                    if (characterObj.description) {
                        charButton.dataset.characterDescription = characterObj.description;
                    }
                    charButton.innerHTML = `<i class="fas fa-user"></i> ${characterObj.name}`;
                    charButton.addEventListener('click', (event) => selectCharacter(characterObj.name, characterObj.description, event.currentTarget));
                    charactersContainer.appendChild(charButton);
                    nonImportantCharactersFound = true; // Mark that we found at least one non-important character
                });
            }

            if (!nonImportantCharactersFound) { // If no non-important characters were rendered (either none existed or all were filtered)
                charactersContainer.innerHTML = '<div class="character-item empty"><i class="fas fa-user-slash"></i> Ở đây không có ai</div>';
            }
            document.getElementById('location-details').classList.remove('hidden');
        }

        function selectCharacter(characterName, characterDescription, triggerElement) {
            selectedCharacterName = characterName;
            const isImportantCharacter = !selectedSub; // True if selectedSub is null

            if (isImportantCharacter) {
                // Explicitly nullify location context for important characters
                // This reinforces that their interaction is global, not tied to a specific sub-location.
                selectedMain = null;
                selectedSub = null;
                console.log("Selected an important character. Ensuring selectedMain and selectedSub are null.");
            }

            // Visual selection handling
            // Deselect all character items in sub-locations and important character buttons first
            document.querySelectorAll('#location-characters .character-item.selected').forEach(btn => btn.classList.remove('selected'));
            document.querySelectorAll('#important-character-buttons .partner-button.selected').forEach(btn => btn.classList.remove('selected'));

            if (triggerElement) { // Highlight the clicked button
                triggerElement.classList.add('selected');
            }

             const modal = document.getElementById('character-modal');
             const modalName = document.getElementById('modal-character-name');
             const modalDescription = document.getElementById('modal-character-description');
             const modalOptionsContainer = document.getElementById('modal-interaction-options');

             modalDescription.textContent = '';
             modalOptionsContainer.innerHTML = '';
             modalName.textContent = characterName;

            let interactionOptions = [];
            let descriptionParts = [];

            if (characterDescription) {
                const allParts = characterDescription.split(';').map(p => p.trim()).filter(p => p);
                let optionsFound = false;
                allParts.forEach(part => {
                    if (optionsFound) {
                        interactionOptions.push(part);
                    } else if (part.startsWith('Tùy chọn tương tác:')) {
                        const firstOption = part.substring('Tùy chọn tương tác:'.length).trim();
                        if (firstOption) interactionOptions.push(firstOption);
                        optionsFound = true;
                    } else {
                        descriptionParts.push(part.replace(':', ': '));
                    }
                });
            }

            modalDescription.textContent = descriptionParts.length > 0 ? descriptionParts.join('\n') : '(Không có thêm thông tin)';

            if (interactionOptions.length > 0) {
                interactionOptions.slice(0, 4).forEach(optionText => {
                    const button = document.createElement('button');
                    button.className = 'interaction-button';
                    button.textContent = optionText;
                    button.addEventListener('click', () => {
                         modal.classList.add('hidden');
                         if (isImportantCharacter) {
                             confirmGlobalCharacterInteraction(optionText); // New function for important chars
                         } else {
                             confirmInteraction(optionText); // Existing function for NPCs
                         }
                    });
                    modalOptionsContainer.appendChild(button);
                });
            } else {
                 modalOptionsContainer.innerHTML = '<p class="info-message">Không có tùy chọn tương tác nào.</p>';
            }

            modal.classList.remove('hidden');
            const characterModalDialog = modal.querySelector('.character-modal-dialog');
            requestAnimationFrame(() => positionModalCenter(characterModalDialog));
        }

        function closeCharacterModal() {
            document.getElementById('character-modal').classList.add('hidden');
            selectedCharacterName = null;
             document.querySelectorAll('#location-characters .character-item.selected').forEach(btn => {
                btn.classList.remove('selected');
            });
            // Also deselect important character buttons if any were selected
            document.querySelectorAll('#important-character-buttons .partner-button.selected').forEach(btn => {
                btn.classList.remove('selected');
            });
        }

        // New function for confirming interaction with important characters
        function confirmGlobalCharacterInteraction(optionText) {
            if (!selectedCharacterName) {
                console.error("confirmGlobalCharacterInteraction: selectedCharacterName is missing.");
                return;
            }

            const confirmTitle = document.getElementById('confirm-title');
            const confirmMessage = document.getElementById('confirm-message');
            const executeBtn = document.getElementById('execute-action-btn');

            confirmTitle.textContent = 'Xác nhận tương tác toàn cục';
            confirmMessage.textContent = `Bạn có muốn thực hiện tương tác "${optionText}" với nhân vật quan trọng ${selectedCharacterName} không?`;
            executeBtn.innerHTML = `<i class="fas fa-check"></i> Xác nhận tương tác`;

            const interactionHandler = () => executeGlobalCharacterInteraction(optionText);
            const newExecuteBtn = executeBtn.cloneNode(true);
            executeBtn.parentNode.replaceChild(newExecuteBtn, executeBtn);
            newExecuteBtn.addEventListener('click', interactionHandler, { once: true });

            const confirmOverlay = document.getElementById('confirm-overlay');
            const confirmDialog = confirmOverlay.querySelector('.confirm-dialog');
            confirmOverlay.classList.remove('hidden');
            requestAnimationFrame(() => positionModalCenter(confirmDialog));
        }

        // New function for executing interaction with important characters
        function executeGlobalCharacterInteraction(optionText) {
            if (!selectedCharacterName) {
                document.getElementById('confirm-overlay').classList.add('hidden');
                console.error("executeGlobalCharacterInteraction: selectedCharacterName is missing.");
                return;
            }

            const cleanCharacterName = selectedCharacterName.replace(/[<>]/g, '');
            const cleanOptionText = optionText.replace(/[<>]/g, '');
            // For global characters, the location might be less specific or implied
            const message = `<request:{{user}}đã thực hiện tương tác "${cleanOptionText}" với nhân vật quan trọng ${cleanCharacterName}>`;

            sendGameActionRequest(message, "Tương tác toàn cục thất bại");
            document.getElementById('confirm-overlay').classList.add('hidden');
            // Deselect the important character button after interaction
            document.querySelectorAll('#important-character-buttons .partner-button.selected').forEach(btn => btn.classList.remove('selected'));
            selectedCharacterName = null; // Clear selection
        }


        function confirmInteraction(optionText) {
             if (!selectedCharacterName || !selectedSub || !selectedMain) {
                 console.error("confirmInteraction: Missing context (character, sub-location, or main-location).");
                 return;
             }

             const locationName = `${selectedMain.name} - ${selectedSub.name}`;
             const confirmTitle = document.getElementById('confirm-title');
             const confirmMessage = document.getElementById('confirm-message');
             const executeBtn = document.getElementById('execute-action-btn');

             confirmTitle.textContent = 'Xác nhận tương tác';
             confirmMessage.textContent = `Bạn có muốn thực hiện tương tác "${optionText}" với ${selectedCharacterName} không? (Địa điểm: ${locationName})`;
             executeBtn.innerHTML = `<i class="fas fa-check"></i> Xác nhận tương tác`;

             const interactionHandler = () => executeInteraction(optionText);
             const newExecuteBtn = executeBtn.cloneNode(true); // Re-attach listener
