        // Renamed and modified function for auto-saving with similarity check
        function saveMapStateWithCheck() {
            if (!mapData || !mapData.title) {
                console.warn("Auto-save skipped: Missing mapData or title.");
                return;
            }

            const currentTimestamp = new Date().toISOString();
            const currentTitle = mapData.title;
            console.log(`Attempting to auto-save state for map: "${currentTitle}"`);

            // --- 1. Save/Update Map State (with prefix-based deduplication) ---
            const allMapSaves = getAllSavedData(); // Uses SAVE_STORAGE_KEY
            const currentPrefix = currentTitle.substring(0, 2); // Get the first two characters as prefix

            // Find and remove all existing saves that share the same first two characters
            const keysToDelete = [];
            for (const existingTitle in allMapSaves) {
                if (allMapSaves.hasOwnProperty(existingTitle)) {
                    if (existingTitle.substring(0, 2) === currentPrefix) {
                        keysToDelete.push(existingTitle);
                    }
                }
            }

            if (keysToDelete.length > 0) {
                console.log(`Found ${keysToDelete.length} existing map(s) with prefix "${currentPrefix}". Removing them to keep only the latest version.`);
                keysToDelete.forEach(key => {
                    // Don't delete if the key to delete is the current title AND we only found one match (it means we are just updating it)
                    // However, if currentTitle is "东海-A" and we found "东海-B", "东海-B" should be deleted.
                    // The new logic is: always delete all old ones with the prefix, then add the new one.
                    delete allMapSaves[key];
                    console.log(`  Removed: "${key}"`);
                });
            }

            // Prepare the data to save for the current title
            const mapSaveData = {
                mapData: mapData, // This is the full mapData object
                timestamp: currentTimestamp
            };

            // Save the current map data under its full title.
            // All previous versions with the same prefix have been removed.
            allMapSaves[currentTitle] = mapSaveData;
            console.log(`Saving new/updated map state for "${currentTitle}" with prefix "${currentPrefix}".`);

            // Save the modified allMapSaves object back to localStorage
            try {
                localStorage.setItem(SAVE_STORAGE_KEY, JSON.stringify(allMapSaves));
                console.log(`Successfully auto-saved map state. Saved as: "${currentTitle}". Total saves: ${Object.keys(allMapSaves).length}`);
            } catch (e) {
                console.error(`Error auto-saving map data to localStorage for key "${currentTitle}":`, e);
            }

            // --- 2. Update Global Character Store (Only Important Characters) ---
            const oldGlobalCharacters = getGlobalCharacters(); // Get existing characters to compare against
            const newGlobalCharacters = {}; // Start with a fresh object for the new state
            let charactersUpdated = false;
            // const currentTimestamp = new Date().toISOString(); // This is already defined earlier in the function

            if (mapData.importantCharacters && Array.isArray(mapData.importantCharacters)) {
                mapData.importantCharacters.forEach(charObj => {
                    if (charObj && charObj.name) {
                        const charName = charObj.name.trim();
                        const charDescription = charObj.description || null; // Keep description as is

                        newGlobalCharacters[charName] = {
                            description: charDescription,
                            timestamp: currentTimestamp // currentTimestamp from outer scope
                        };
                        console.log(`[Character Save] Preparing important character "${charName}" for global store.`);
                    }
                });
            }

            // Compare the newly constructed important character list with the old global character list
            // This determines if an actual save operation is needed.
            if (JSON.stringify(oldGlobalCharacters) !== JSON.stringify(newGlobalCharacters)) {
                charactersUpdated = true;
            }

            // Save the new global character store if changes were made
            if (charactersUpdated) {
                saveGlobalCharacters(newGlobalCharacters); // Save the new set (could be empty if no important chars)
                console.log("Global character store updated. Now contains only current important characters.");
            } else {
                console.log("No changes to important characters list; global character store remains the same.");
            }
        } // End of saveMapStateWithCheck function

        // --- New Function: Delete Saved Item ---
        function deleteSavedItem(itemName, itemType) {
            const typeText = itemType === 'map' ? 'Địa điểm' : 'Nhân vật';
            const storageKey = itemType === 'map' ? SAVE_STORAGE_KEY : CHARACTER_STORAGE_KEY;

