                        allData = getAllSavedData(); // Uses SAVE_STORAGE_KEY
                    } else {
                        allData = getGlobalCharacters(); // Uses CHARACTER_STORAGE_KEY
                    }

                    if (allData.hasOwnProperty(itemName)) {
                        delete allData[itemName]; // Remove the item

                        // Save the updated data back
                        if (itemType === 'map') {
                            localStorage.setItem(SAVE_STORAGE_KEY, JSON.stringify(allData));
                        } else {
                            saveGlobalCharacters(allData); // Uses CHARACTER_STORAGE_KEY
                        }

                        console.log(`Successfully deleted ${typeText}: "${itemName}"`);
                        alert(`${typeText} "${itemName}" đã được xóa.`);
                        populateSaveLoadModal(); // Refresh the modal list
                    } else {
                        console.warn(`Attempted to delete non-existent ${typeText}: "${itemName}"`);
                        alert(`Xóa thất bại: không tìm thấy ${typeText} "${itemName}".`);
                    }
                } catch (e) {
                    console.error(`Error deleting ${typeText} "${itemName}" from localStorage:`, e);
                    alert(`Đã xảy ra lỗi khi xóa ${typeText}.`);
                }
            }
        }
