        function loadMapState(mapTitle) {
            console.log(`Requesting AI to load map state for: "${mapTitle}"`);
            const allSaves = getAllSavedData();
            const saveData = allSaves[mapTitle];

        if (saveData && saveData.mapData) {
            try {
                // Log 2: Check the structure of saveData.mapData before formatting
                // Log 2: Check the structure of saveData.mapData before processing
                console.log(`[DEBUG] Found mapData for "${mapTitle}", attempting to extract title and sublocations. Data type: ${typeof saveData.mapData}, Keys: ${saveData.mapData ? Object.keys(saveData.mapData).join(', ') : 'N/A'}`);
                console.log('[DEBUG] saveData.mapData object:', saveData.mapData); // Log the actual object

                const cleanMapTitle = mapTitle.replace(/[<>]/g, ''); // Sanitize title

                // --- Start: Construct condensed message ---
                let condensedContent = `[TITLE: ${cleanMapTitle}]\n`; // Start with the title

                if (saveData.mapData.locations && Array.isArray(saveData.mapData.locations)) {
                    saveData.mapData.locations.forEach(loc => {
                        if (loc.subLocations && Array.isArray(loc.subLocations)) {
                            loc.subLocations.forEach(sub => {
                                condensedContent += `- ${sub.name}: `;
                                if (sub.characters && Array.isArray(sub.characters) && sub.characters.length > 0) {
                                    const charStr = sub.characters.map(char => {
                                        let charOutput = char.name;
                                        // Append description in brackets if it exists
                                        if (char.description) {
                                            charOutput += `{${char.description}}`;
                                        }
                                        return charOutput;
                                    }).join(', ');
                                    condensedContent += `${charStr}\n`;
                                } else {
                                    condensedContent += `Không có\n`; // Indicate no characters if array is empty or missing
                                }
                            });
                        }
                    });
                }
