        function sendCustomInteraction() {
            const inputElement = document.getElementById('custom-interaction-input');
            const customText = inputElement.value.trim();
            if (!customText) { inputElement.focus(); return; }

            if (!selectedCharacterName) {
                 alert("Không thể gửi tin nhắn, chưa chọn nhân vật."); return;
            }

            let locationName;
            let interactionPrefix;
            let message;

            if (selectedSub && selectedMain) { // Interacting with NPC in a sub-location
                locationName = `${selectedMain.name} - ${selectedSub.name}`;
                interactionPrefix = `nói với ${selectedCharacterName}`;
                const cleanLocationName = locationName.replace(/[<>]/g, '');
                const cleanCharacterName = selectedCharacterName.replace(/[<>]/g, '');
                const cleanCustomText = customText.replace(/[<>]/g, '');
                message = `<request:{{user}}${interactionPrefix}：“${cleanCustomText}”. Tại ${cleanLocationName}>`;
            } else if (selectedCharacterName) { // Interacting with an important character (selectedSub is null)
                locationName = "Đối thoại toàn cục";
                interactionPrefix = `nói với nhân vật quan trọng ${selectedCharacterName}`;
                const cleanCharacterName = selectedCharacterName.replace(/[<>]/g, '');
                const cleanCustomText = customText.replace(/[<>]/g, '');
                message = `<request:{{user}}${interactionPrefix}：“${cleanCustomText}”>`; // Location might be omitted or handled differently by AI for global
            } else {
                alert("Không thể gửi tin nhắn, ngữ cảnh không rõ ràng."); return;
            }

            sendGameActionRequest(message, "Gửi tin nhắn tùy chỉnh thất bại");
            inputElement.value = '';
            closeCharacterModal();
        }

