        function findCharacterInMapData(characterName, locations = []) {
            if (!locations) return null;
            for (const mainLoc of locations) {
                if (!mainLoc || !Array.isArray(mainLoc.subLocations)) continue;
                for (const subLoc of mainLoc.subLocations) {
                    if (!subLoc || !Array.isArray(subLoc.characters)) continue;
                    const foundChar = subLoc.characters.find(char => char && char.name === characterName);
                    if (foundChar) {
                        // Return character data along with its location context
                        return { ...foundChar, mainLocationName: mainLoc.name, subLocationName: subLoc.name };
                    }
                }
            }
            return null; // Character not found anywhere
        }

        function handleNewMessage(messageData) {
            // Basic check if message is from user or system/character
            if (!messageData || messageData.is_user || !mapData || !mapData.locations) {
                return; // Ignore user messages or if map isn't loaded
            }

            const messageContent = messageData.mes; // Assuming 'mes' holds the text content

            // Attempt to extract location from message (example pattern, adjust as needed)
            // This pattern looks for "> Tại [Main Location] - [Sub Location]" at the end
            const locationMatch = messageContent.match(/Tại\s*([^->]+?)\s*-\s*([^>]+?)>/);
            if (locationMatch && locationMatch[1] && locationMatch[2]) {
                const mainLocName = locationMatch[1].trim();
                const subLocName = locationMatch[2].trim();

                console.log(`Message indicates location: ${mainLocName} - ${subLocName}`);

                const targetMainLocation = mapData.locations.find(loc => loc.name === mainLocName);
                if (targetMainLocation) {
                    const targetSubLocation = targetMainLocation.subLocations.find(sub => sub.name === subLocName);
                    if (targetSubLocation) {
                        // Found the location, select it on the map
                        console.log("Auto-selecting location from message...");
                        selectMainLocation(targetMainLocation);
                        // Use requestAnimationFrame to ensure UI updates before selecting sub-location
                        requestAnimationFrame(() => {
                            // Double-check if main location is still selected (user might have clicked elsewhere)
                            if (selectedMain && selectedMain.name === mainLocName) {
                                // Find sub-location again within the currently selected main location
                                const currentTargetSubLocation = selectedMain.subLocations.find(sub => sub.name === subLocName);
                                if (currentTargetSubLocation) {
                                    // Delay slightly to ensure main location selection UI is finished
                                    setTimeout(() => {
                                        selectSubLocation(currentTargetSubLocation);
                                        console.log("Sub-location selected.");
                                    }, 50); // 50ms delay, adjust if needed
                                } else {
                                     console.log("Sub-location not found within currently selected main location.");
                                }
                            } else {
                                 console.log("Main location changed before sub-location could be selected.");
                            }
                        });
                        return; // Stop further processing for this message
                    } else {
                         console.log(`Sub-location "${subLocName}" not found in main location "${mainLocName}".`);
                    }
                } else {
                     console.log(`Main location "${mainLocName}" not found.`);
                }
            } else {
                 console.log("Message does not contain location pattern.");
            }
        }

