            document.documentElement.style.setProperty('--theme-bg-dark', settings.uiBgColor);
            document.documentElement.style.setProperty('--font-size-base', settings.fontSize);

            // Calculate derived colors
            try {
                const calculateColor = (hex, amount) => {
                    let r = parseInt(hex.slice(1, 3), 16);
                    let g = parseInt(hex.slice(3, 5), 16);
                    let b = parseInt(hex.slice(5, 7), 16);
                    r = Math.min(255, r + amount); g = Math.min(255, g + amount); b = Math.min(255, b + amount);
                    return `#${r.toString(16).padStart(2, '0')}${g.toString(16).padStart(2, '0')}${b.toString(16).padStart(2, '0')}`;
                };
                document.documentElement.style.setProperty('--theme-accent-orange-light', calculateColor(settings.uiColor, 30));
                document.documentElement.style.setProperty('--theme-button-hover-color', calculateColor(settings.buttonColor, 20));
                document.documentElement.style.setProperty('--theme-bg-medium', calculateColor(settings.uiBgColor, 18));
                document.documentElement.style.setProperty('--theme-bg-light', calculateColor(settings.uiBgColor, 36));
                document.documentElement.style.setProperty('--theme-border-light', calculateColor(settings.uiBgColor, 50));
            } catch (e) {
                console.error("Error calculating derived UI colors:", e);
                // Apply fallbacks if calculation fails
                document.documentElement.style.setProperty('--theme-accent-orange-light', settings.uiColor);
                document.documentElement.style.setProperty('--theme-button-hover-color', settings.buttonColor);
