    <style>
        @import url('https://fonts.googleapis.com/css2?family=ZCOOL+XiaoWei&family=ZCOOL+QingKe+HuangYou&display=swap');

        :root {
            /* Base Colors & Fonts (controlled by JS/Settings) */
            --theme-bg-dark: #2c313a;
            --theme-bg-medium: #3e4451;
            --theme-bg-light: #505663;
            --theme-text-light: #e6e6e6;
            --theme-text-medium: #b0b0b0;
            --theme-text-dark: #222222;
            --theme-accent-orange: #e8a85e;
            --theme-accent-orange-light: #f5c58a;
            --theme-button-color: #7cb342;
            --theme-button-hover-color: #8fd352;
            --theme-border-light: #606673;
            --font-title: "ZCOOL QingKe HuangYou", "Microsoft YaHei", sans-serif;
            --font-main: "ZCOOL XiaoWei", "Microsoft YaHei", sans-serif;
            --font-size-base: 13px;

            /* Derived/Static Colors & UI Elements */
            --theme-border-accent: var(--theme-accent-orange);
            --theme-success: #7cb342;
            --theme-success-hover: #8fd352;
            --theme-cancel-bg: #78909c;
            --theme-cancel-hover: #90a4ae;
            --border-radius-base: 8px;
            --border-radius-small: 5px;
            --icon-size-button: 1em;
            --shadow-subtle: 0 2px 5px rgba(0, 0, 0, 0.2);
            --shadow-medium: 0 4px 10px rgba(0, 0, 0, 0.25);

            /* Map Specific Styles */
            --map-rect-stroke: #6a6f7c;
            --map-rect-stroke-hover: var(--theme-accent-orange-light);
            --map-rect-stroke-selected: var(--theme-accent-orange);
            --map-label-fill: var(--theme-text-light);
            --map-label-fill-selected: var(--theme-text-dark);
            --map-current-stroke: var(--theme-accent-orange);
            --map-current-label-fill: var(--theme-text-dark);
            --map-road-stroke: #777c88;
            --map-bg-pattern: radial-gradient(circle at 1px 1px, rgba(255,255,255,0.03) 1px, transparent 0);
        }

        html { font-size: var(--font-size-base); }
        body {
            background-color: transparent; margin: 0; padding: 10px;
            font-family: var(--font-main); color: var(--theme-text-light);
            box-sizing: border-box; font-weight: 400;
        }
        .map-interface {
            max-width: 100%; width: 100%; margin: 0 auto;
            background: var(--theme-bg-dark); border: 2px solid var(--theme-border-light);
            border-radius: var(--border-radius-base); box-shadow: var(--shadow-medium);
            padding: 20px; box-sizing: border-box; position: relative;
            overflow: hidden; min-height: 700px; z-index: 100;
        }
        .map-header {
            text-align: center; margin-bottom: 25px; padding-bottom: 15px;
            border-bottom: 1px solid var(--theme-border-light);
        }
        .map-header h2 {
            font-size: 1.85rem; margin: 0; padding: 0; line-height: 1.4;
            color: var(--theme-accent-orange-light); font-family: var(--font-title);
            font-weight: normal; position: relative; text-shadow: 1px 1px 2px rgba(0,0,0,0.3);
        }
        .current-partners-section {
            margin-bottom: 25px; padding: 15px;
            background-color: rgba(232, 168, 94, 0.1); border: 1px solid var(--theme-accent-orange);
            border-radius: var(--border-radius-base); display: block; box-shadow: var(--shadow-subtle);
        }
        .current-partners-section.hidden { display: none; }
        .current-partners-section .section-title {
            margin-bottom: 12px; color: var(--theme-accent-orange-light); font-weight: bold;
        }
        .partner-button-list { display: flex; flex-wrap: wrap; gap: 10px; }
        .partner-button {
            background-color: var(--theme-bg-light); border: 1px solid var(--theme-border-light);
            border-radius: var(--border-radius-small); padding: 7px 14px; font-size: 1rem;
            color: var(--theme-text-light); cursor: pointer; transition: all 0.2s ease;
            display: inline-flex; align-items: center; box-shadow: var(--shadow-subtle);
        }
        .partner-button i { margin-right: 6px; color: var(--theme-accent-orange); }
        .partner-button:hover {
            background-color: var(--theme-border-light); border-color: var(--theme-accent-orange-light);
            transform: translateY(-1px); box-shadow: var(--shadow-medium);
        }
        .movement-alert {
            background-color: rgba(224, 172, 105, 0.2); border: 1px solid var(--theme-accent-orange);
            border-radius: var(--border-radius-small); padding: 12px; margin-bottom: 20px;
            text-align: center; color: var(--theme-accent-orange-light);
        }
        .movement-alert.hidden { display: none; }
        .movement-alert i { margin-right: 8px; }

        /* Visual Map SVG Styles */
        #visual-map-container {
            position: relative; width: 100%; max-width: 800px; margin: 0 auto 25px auto;
            border: 2px solid var(--theme-border-light); background-color: var(--theme-bg-medium);
            background-image: var(--map-bg-pattern); background-size: 10px 10px;
            border-radius: var(--border-radius-base); overflow: hidden; aspect-ratio: 800 / 600;
            box-shadow: var(--shadow-medium); pointer-events: auto; z-index: 1;
        }
        #visual-map { display: block; width: 100%; height: 100%; pointer-events: auto; }
        .map-location-group {
            cursor: pointer; transition: transform 0.2s ease, filter 0.2s ease;
            filter: drop-shadow(1px 1px 1px rgba(0,0,0,0.3)); transform-origin: center center;
            pointer-events: auto;
        }
        .map-location-group:not(.current-location):hover { filter: drop-shadow(2px 2px 3px rgba(0,0,0,0.4)); }
        .map-location-group:not(.current-location):hover .map-location-rect {
            fill: var(--theme-border-light); stroke: var(--map-rect-stroke-hover);
        }
        .map-location-group.selected { filter: drop-shadow(2px 2px 3px rgba(0,0,0,0.4)); }
        .map-location-group.selected .map-location-rect {
            fill: var(--theme-accent-orange); stroke: var(--map-rect-stroke-selected); stroke-width: 2.5px;
        }
        .map-location-group.selected .map-location-label { font-weight: bold; text-shadow: none; }
        .map-location-rect {
            fill: var(--theme-bg-light); stroke: var(--map-rect-stroke); stroke-width: 1.5px;
            transition: fill 0.2s ease, stroke 0.2s ease, stroke-width 0.2s ease;
        }
        .map-location-label {
            fill: var(--map-label-fill); font-family: var(--font-main); font-size: 0.92rem;
            text-anchor: middle; dominant-baseline: middle; pointer-events: none; user-select: none;
            transition: fill 0.2s ease, font-weight 0.2s ease, text-shadow 0.2s ease;
            text-shadow: 1px 1px 1px rgba(0,0,0,0.5);
        }
        .map-location-group.current-location { cursor: default; filter: drop-shadow(1px 1px 2px rgba(0,0,0,0.4)); }
        .map-location-group.current-location .map-location-rect {
            fill: var(--theme-accent-orange-light); stroke: var(--map-current-stroke); stroke-width: 2.5px;
        }
        .map-location-group.current-location .map-location-label {
            fill: var(--map-current-label-fill); font-weight: bold; text-shadow: none;
        }
        .map-tooltip {
            position: fixed; background-color: rgba(44, 49, 58, 0.95); color: var(--theme-text-light);
            border: 1px solid var(--theme-border-light); border-radius: var(--border-radius-small);
            padding: 6px 12px; font-size: 0.92rem; white-space: nowrap; z-index: 1010;
            pointer-events: none; opacity: 0; transition: opacity 0.15s ease; box-shadow: var(--shadow-subtle);
        }
        .map-tooltip.visible { opacity: 1; }
        .map-road {
            stroke: var(--map-road-stroke); stroke-linecap: round; stroke-linejoin: round;
            filter: drop-shadow(1px 1px 1px rgba(0,0,0,0.2));
        }
        .current-user-position { /* Style for the red dot */
             /* Fill, stroke, etc., set by JS */
        }

        /* Sub-locations & Details */
        .sub-location-grid {
            display: grid; grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
            gap: 12px; margin-bottom: 25px; padding: 18px; background-color: var(--theme-bg-medium);
            border-radius: var(--border-radius-base); border: 1px solid var(--theme-border-light);
            transition: opacity 0.3s ease, max-height 0.4s ease, box-shadow 0.3s ease;
            opacity: 1; max-height: 1000px; overflow: hidden; box-shadow: var(--shadow-subtle);
        }
        .sub-location-grid.hidden {
            opacity: 0; max-height: 0; padding-top: 0; padding-bottom: 0; margin-bottom: 0; border: none; box-shadow: none;
        }
        .sub-location-button {
            background-color: var(--theme-bg-light); border: 1px solid var(--theme-border-light);
            border-radius: var(--border-radius-small); padding: 10px 15px; color: var(--theme-text-light);
            font-family: var(--font-main); font-size: 1rem; cursor: pointer; transition: all 0.2s ease;
            text-align: left; box-shadow: var(--shadow-subtle); display: flex; align-items: center;
            overflow: hidden; text-overflow: ellipsis; white-space: nowrap;
        }
        .sub-location-button i { margin-right: 8px; color: var(--theme-accent-orange); transition: color 0.2s ease; flex-shrink: 0; }
        .sub-location-button:hover:not(.disabled) {
            background-color: var(--theme-border-light); border-color: var(--theme-accent-orange-light);
            transform: translateY(-1px); box-shadow: var(--shadow-medium);
        }
        .sub-location-button.selected {
            background: linear-gradient(to bottom, var(--theme-accent-orange-light), var(--theme-accent-orange));
            border-color: var(--theme-accent-orange); color: var(--theme-text-dark);
            box-shadow: var(--shadow-medium); transform: translateY(-1px); font-weight: bold;
        }
        .sub-location-button.selected i { color: var(--theme-text-dark); }
        .location-details {
            margin-top: 25px; padding: 25px; background-color: var(--theme-bg-medium);
            border-radius: var(--border-radius-base); border: 1px solid var(--theme-border-light);
            box-shadow: var(--shadow-medium);
            transition: opacity 0.3s ease, transform 0.3s ease, max-height 0.4s ease;
            opacity: 1; max-height: 1000px; overflow: hidden; transform: translateY(0);
        }
        .location-details.hidden {
             opacity: 0; max-height: 0; padding-top: 0; padding-bottom: 0; margin-top: 0; border: none; transform: translateY(-10px); box-shadow: none;
        }
        .detail-header {
            font-size: 1.38rem; margin-bottom: 20px; padding-bottom: 12px;
            border-bottom: 1px solid var(--theme-border-light); color: var(--theme-accent-orange-light);
            text-align: center; font-weight: bold;
        }
        .detail-header i { margin-right: 10px; }
        .section-title {
            font-size: 1.15rem; color: var(--theme-text-medium); margin-bottom: 15px;
            font-weight: bold; border-bottom: 1px dashed var(--theme-border-light); padding-bottom: 5px;
        }
        .section-title i { margin-right: 8px; color: var(--theme-accent-orange); }
        .character-list {
            display: grid; grid-template-columns: repeat(auto-fill, minmax(130px, 1fr));
            gap: 10px; margin-bottom: 25px;
        }
        .character-item {
            background-color: var(--theme-bg-light); border: 1px solid var(--theme-border-light);
            border-radius: var(--border-radius-small); padding: 9px 12px; font-size: 1rem;
            color: var(--theme-text-light); transition: all 0.2s ease; display: flex; align-items: center;
            overflow: hidden; text-overflow: ellipsis; white-space: nowrap; cursor: pointer;
            text-align: left; box-shadow: var(--shadow-subtle);
        }
        .character-item:hover:not(.empty) {
             background-color: var(--theme-border-light); border-color: var(--theme-accent-orange-light);
             transform: translateY(-1px); box-shadow: var(--shadow-medium);
        }
        .character-item.selected {
            background: linear-gradient(to bottom, var(--theme-accent-orange-light), var(--theme-accent-orange));
            border-color: var(--theme-accent-orange); color: var(--theme-text-dark);
            box-shadow: var(--shadow-medium); transform: translateY(-1px); font-weight: bold;
        }
         .character-item.selected i { color: var(--theme-text-dark); }
        .character-item i { margin-right: 7px; color: var(--theme-accent-orange); flex-shrink: 0; }
        .character-item.empty {
            color: var(--theme-text-medium); background-color: transparent;
            border: 1px dashed var(--theme-border-light); justify-content: center; opacity: 0.7;
            cursor: default; grid-column: 1 / -1; text-align: center; box-shadow: none; padding: 8px 10px;
        }
        .character-item.empty i { color: var(--theme-text-medium); margin: 0 5px 0 0; }

        /* Action Buttons */
        .action-section { margin-top: 25px; text-align: center; }
        .action-button { /* Main action button (Go To) */
            background: var(--theme-button-color); color: white; border: none;
            border-radius: var(--border-radius-small); padding: 12px 30px; font-size: 16px;
            font-weight: 500; cursor: pointer; transition: all 0.2s ease;
            box-shadow: var(--shadow-subtle); display: inline-flex; align-items: center;
            justify-content: center; text-shadow: 1px 1px 1px rgba(0,0,0,0.2);
        }
        .action-button:hover:not(:disabled) {
            background: var(--theme-button-hover-color); box-shadow: var(--shadow-medium);
            transform: translateY(-1px);
        }
        .action-button:active:not(:disabled) { transform: translateY(0px); box-shadow: var(--shadow-subtle); }
        .action-button:disabled {
             opacity: 0.6; cursor: not-allowed; background: var(--theme-cancel-bg);
             box-shadow: none; text-shadow: none;
        }
        .action-button i { margin-right: 10px; }
        .switch-area-section { text-align: center; margin-bottom: 25px; }
