            display: inline-flex; align-items: center; justify-content: center;
            text-shadow: 1px 1px 1px rgba(0,0,0,0.1);
        }
        .switch-area-button i { margin-right: 10px; color: var(--theme-accent-orange); transition: color 0.2s ease; }
        .switch-area-button:hover:not(.selected) {
            background: linear-gradient(to bottom, var(--theme-border-light), var(--theme-bg-light));
            border-color: var(--theme-accent-orange-light); transform: translateY(-1px); box-shadow: var(--shadow-medium);
        }
        .switch-area-button.selected {
            background: linear-gradient(to bottom, var(--theme-accent-orange-light), var(--theme-accent-orange));
            border-color: var(--theme-accent-orange); color: var(--theme-text-dark);
            box-shadow: var(--shadow-medium); transform: translateY(-1px); font-weight: bold; text-shadow: none;
        }
        .switch-area-button.selected i { color: var(--theme-text-dark); }
        .switch-area-button.hidden { display: none; }

        /* Modals */
        .modal-overlay {
            position: fixed; top: 0; left: 0; width: 100%; height: 100%;
