        .confirm-button { background: var(--theme-button-color); color: white; }
        .confirm-button:hover { background: var(--theme-button-hover-color); box-shadow: var(--shadow-medium); transform: translateY(-1px); }
        .dialog-button i { margin-right: 8px; }
        .character-modal-dialog { padding: 25px 30px 30px 30px; width: 90%; max-width: 450px; position: relative; }
        .close-modal-button {
